package com.user.servlet; import com.DB.DBConnect; import com.DAO.BookDAOImpl; import javax.servlet.annotation.WebServlet; import javax.servlet.http.*; import java.io.*;
@WebServlet("/delete_old_book") public class DeleteOldBook extends HttpServlet {protected void doGet(HttpServletRequest r,HttpServletResponse p)throws IOException{try(var c=DBConnect.getConn()){boolean ok=new BookDAOImpl(c).oldBookDelete(r.getParameter("em"),"Old",Integer.parseInt(r.getParameter("id")));r.getSession().setAttribute(ok?"succMsg":"failedMsg",ok?"Book deleted":"Delete failed");}catch(Exception e){r.getSession().setAttribute("failedMsg",e.getMessage());}p.sendRedirect("old_book.jsp");}}
